arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Existing 500K documents and direct SQL queries use "Discriminator".
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id.
        // Existing documents have ids like "Product|123"; preserve that format.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // Removed HasIndex — EF Core 9 Cosmos provider throws on HasIndex.
    // Manage indexing via the Cosmos DB container's indexing policy instead.
}

